cat > /tmp/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Collect all errors
var errors = new List<(string project, string code, string message, string file, int line)>();
// Collect all warnings  
var warnings = new List<(string project, string code, string message, string file, int line)>();

build.VisitAllChildren<Error>(e => {
    var proj = "";
    var parent = e.Parent;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    errors.Add((proj, e.Code ?? "", e.Text ?? "", e.File ?? "", e.LineNumber ?? 0));
});

build.VisitAllChildren<Warning>(w => {
    var proj = "";
    var parent = w.Parent;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent;
    }
    warnings.Add((proj, w.Code ?? "", w.Text ?? "", w.File ?? "", w.LineNumber ?? 0));
});

Console.WriteLine("=== BUILD ERRORS ===");
Console.WriteLine($"Total errors: {errors.Count}");
Console.WriteLine();
foreach (var g in errors.GroupBy(e => e.project))
{
    Console.WriteLine($"--- Project: {g.Key} ---");
    foreach (var e in g)
    {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
    }
    Console.WriteLine();
}

Console.WriteLine("=== BUILD WARNINGS ===");
Console.WriteLine($"Total warnings: {warnings.Count}");
Console.WriteLine();
foreach (var g in warnings.GroupBy(w => w.project))
{
    Console.WriteLine($"--- Project: {g.Key} ---");
    foreach (var w in g)
    {
        Console.WriteLine($"  [{w.code}] {w.file}({w.line}): {w.message}");
    }
    Console.WriteLine();
}

// Also dump project evaluation/build results
Console.WriteLine("=== PROJECT BUILD RESULTS ===");
build.VisitAllChildren<Project>(p => {
    Console.WriteLine($"  Project: {p.Name} | Succeeded: {p.Succeeded}");
});
