cat > /tmp/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Extract project references and package references
Console.WriteLine("=== PROJECT REFERENCES & PACKAGE REFERENCES ===");
build.VisitAllChildren<Project>(p => {
    var items = new List<string>();
    var pkgs = new List<string>();
    p.VisitAllChildren<Item>(i => {
        if (i.Parent is Folder f) {
            if (f.Name == "ProjectReference")
                items.Add(i.Text ?? "");
            if (f.Name == "PackageReference")
                pkgs.Add(i.Text ?? "");
        }
    });
    if (items.Count > 0 || pkgs.Count > 0)
    {
        Console.WriteLine($"\n  Project: {p.Name}");
        foreach (var r in items.Distinct()) Console.WriteLine($"    ProjectRef: {r}");
        foreach (var r in pkgs.Distinct()) Console.WriteLine($"    PackageRef: {r}");
    }
});

// Dump source file content from the binlog if available
Console.WriteLine("\n=== SOURCE FILE CONTENT (from binlog) ===");
build.VisitAllChildren<SourceFile>(sf => {
    Console.WriteLine($"  SourceFile: {sf.Name}");
});

// Check for any relevant messages about NuGet restore
Console.WriteLine("\n=== NUGET / RESTORE MESSAGES ===");
build.VisitAllChildren<Message>(m => {
    var text = m.Text ?? "";
    if (text.Contains("Newtonsoft", StringComparison.OrdinalIgnoreCase) ||
        text.Contains("PackageReference", StringComparison.OrdinalIgnoreCase) ||
        text.Contains("restore", StringComparison.OrdinalIgnoreCase) ||
        text.Contains("NU", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine($"  {text.Substring(0, Math.Min(text.Length, 200))}");
    }
});

// Check the source files captured in the compilation
Console.WriteLine("\n=== COMPILE ITEMS FOR Services.csproj ===");
build.VisitAllChildren<Project>(p => {
    if (p.Name == "Services.csproj")
    {
        p.VisitAllChildren<Item>(i => {
            if (i.Parent is Folder f && (f.Name == "Compile" || f.Name == "Reference" || f.Name == "PackageReference" || f.Name == "ProjectReference"))
            {
                Console.WriteLine($"  [{f.Name}] {i.Text}");
            }
        });
    }
});
