cat > /tmp/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

var archive = build.SourceFilesArchive;
using var ms = new System.IO.MemoryStream(archive);
using var zip = new System.IO.Compression.ZipArchive(ms, System.IO.Compression.ZipArchiveMode.Read);

// List ALL .cs files in the archive
Console.WriteLine("=== ALL .cs FILES IN ARCHIVE ===");
foreach (var entry in zip.Entries)
{
    var name = entry.FullName.Replace('\\', '/');
    if (name.EndsWith(".cs"))
    {
        Console.WriteLine($"  {name}");
        using var reader = new System.IO.StreamReader(entry.Open());
        Console.WriteLine(reader.ReadToEnd());
        Console.WriteLine();
    }
}

// Also extract the editorconfig and other generated files for Services
Console.WriteLine("=== GENERATED FILES FOR Services ===");
foreach (var entry in zip.Entries)
{
    var name = entry.FullName.Replace('\\', '/');
    if (name.Contains("Services") && (name.EndsWith(".editorconfig") || name.EndsWith(".g.cs")))
    {
        Console.WriteLine($"\n--- {name} ---");
        using var reader = new System.IO.StreamReader(entry.Open());
        Console.WriteLine(reader.ReadToEnd());
    }
}
