cat > /tmp/BinlogReader/Program.cs << 'CSHARP'
using Microsoft.Build.Logging.StructuredLogger;
using MSTask = Microsoft.Build.Logging.StructuredLogger.Task;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

// Check which projects had Build target succeed/fail
Console.WriteLine("=== TARGET RESULTS ===");
build.VisitAllChildren<Target>(t => {
    var proj = "";
    TreeNode parent = t;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = parent.Parent as TreeNode;
    }
    // Only show key targets
    if (t.Name == "Build" || t.Name == "CoreCompile" || t.Name == "Compile" || t.Name == "Csc" || t.Name == "ResolveProjectReferences")
    {
        Console.WriteLine($"  {proj} -> {t.Name}: Succeeded={t.Succeeded}");
    }
});

// Check for any messages about skipped/failed builds 
Console.WriteLine("\n=== BUILD RESULT MESSAGES ===");
build.VisitAllChildren<Error>(e => {
    var proj = "";
    TreeNode parent = e;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = parent.Parent as TreeNode;
    }
    Console.WriteLine($"  ERROR in {proj}: [{e.Code}] {e.File}({e.LineNumber}): {e.Text}");
});

// Check if Api's Csc task ran at all
Console.WriteLine("\n=== CSC TASK RUNS ===");
build.VisitAllChildren<MSTask>(t => {
    if (t.Name == "Csc")
    {
        var proj = "";
        TreeNode parent = t;
        while (parent != null) {
            if (parent is Project p) { proj = p.Name; break; }
            parent = parent.Parent as TreeNode;
        }
        Console.WriteLine($"  Csc ran in: {proj}, Succeeded: {t.Succeeded}");
    }
});
